import React, { useState, useEffect } from "react";
import "./Timesheet.css";

const projects = [
  "Website Redesign",
  "Mobile App Development",
  "Internal Systems",
  "Client Meetings",
];

const Timesheet = () => {

  /* =========================
        VIEW STATE
  ========================== */
  const [view, setView] = useState("WEEK");   // WEEK | MONTH | SIX | YEAR


  /* =========================
        WEEK HANDLING
  ========================== */
  const getStartOfWeek = (date) => {
    const d = new Date(date);
    const day = d.getDay();
    const diff = d.getDate() - (day === 0 ? 6 : day - 1);
    return new Date(d.setDate(diff));
  };

  const [currentWeekStart, setCurrentWeekStart] = useState(
    getStartOfWeek(new Date())
  );

  const generateWeek = (startDate) => {
    const days = [
      "Monday","Tuesday","Wednesday",
      "Thursday","Friday","Saturday","Sunday"
    ];

    return days.map((day, i) => {
      const d = new Date(startDate);
      d.setDate(d.getDate() + i);

      return {
        day,
        dateText: d.toLocaleDateString("en-US", { month: "short", day: "numeric" }),
        key: d.toISOString().split("T")[0],
        project: "",
        hours: 0,
        description: "",
        isLeave: false,
        leaveStatus: "",
        leaveType: ""
      };
    });
  };


  /* =========================
        STATE
  ========================== */
  const [entries, setEntries] = useState([]);
  const [status, setStatus] = useState("DRAFT");


  /* =====================================================
        ENABLE VIEW BUTTON TO OPEN WEEK FROM HISTORY
  ====================================================== */
  useEffect(() => {
    const selected = localStorage.getItem("selected-week");

    if (selected) {
      setCurrentWeekStart(new Date(selected));
      localStorage.removeItem("selected-week");
    }
  }, []);


  /* =========================
        LOAD WEEK DATA + LEAVES
  ========================== */
  useEffect(() => {
    const saved = localStorage.getItem(currentWeekStart.toISOString());
    const leaves = JSON.parse(localStorage.getItem("employee-leaves")) || [];

    let weekData;

    if (saved) {
      const parsed = JSON.parse(saved);
      weekData = parsed.entries || [];
      setStatus(parsed.status || "DRAFT");
    } else {
      weekData = generateWeek(currentWeekStart);
      setStatus("DRAFT");
    }

    weekData = weekData.map((day) => {
      const leave = leaves.find(l => l.date === day.key);

      if (leave) {
        return {
          ...day,
          isLeave: leave.status === "APPROVED",
          leaveStatus: leave.status,
          leaveType: leave.type
        };
      }

      return day;
    });

    setEntries(weekData);

  }, [currentWeekStart]);


  /* =========================
        SAVE DATA CONTINUOUSLY
  ========================== */
  useEffect(() => {
    if (entries.length === 0) return;

    localStorage.setItem(
      currentWeekStart.toISOString(),
      JSON.stringify({
        entries,
        status
      })
    );

  }, [entries, status, currentWeekStart]);


  /* =========================
        NAVIGATION
  ========================== */
  const changeWeek = (days) => {
    const newDate = new Date(currentWeekStart);
    newDate.setDate(newDate.getDate() + days);
    setCurrentWeekStart(getStartOfWeek(newDate));
  };


  /* =========================
        FIELD HANDLING
  ========================== */
  const handleChange = (index, field, value) => {
    if (status === "SUBMITTED") return;
    if (entries[index].isLeave) return;

    const updated = [...entries];
    updated[index][field] = value;
    setEntries(updated);
  };

  const removeEntry = (index) => {
    if (status === "SUBMITTED") return;
    if (entries[index].isLeave) return;

    const updated = entries.filter((_, i) => i !== index);
    setEntries(updated);
  };

  const addEntry = () => {
    if (status === "SUBMITTED") return;

    const newEntry = {
      day: "Extra Entry",
      dateText: "",
      key: "extra-" + Date.now() + "-" + Math.random(),
      project: "",
      hours: 0,
      description: "",
      isLeave: false
    };

    setEntries(prev => [...prev, newEntry]);
  };


  /* =========================
        HOURS
  ========================== */
  const totalHours = entries.reduce(
    (sum, item) => sum + Number(item.hours || 0),
    0
  );

  const overtime = totalHours > 40 ? totalHours - 40 : 0;


  /* =================================================
        SAVE HISTORY (Draft + Submitted)
  ================================================= */
  const saveHistory = (newStatus) => {

    setStatus(newStatus);

    const weekRange =
      `${entries[0].dateText} - ${entries[6].dateText}`;

    const history = JSON.parse(localStorage.getItem("timesheet-history")) || [];

    const key = currentWeekStart.toISOString();

    const existingIndex = history.findIndex(h => h.key === key);

    const record = {
      key,
      weekRange,
      totalHours,
      status: newStatus,
      timestamp: Date.now()
    };

    if (existingIndex !== -1) {
      history[existingIndex] = record;
    } else {
      history.push(record);
    }

    localStorage.setItem("timesheet-history", JSON.stringify(history));
  };


  /* =========================
        UI
  ========================== */
  return (
    <div className="timesheet-container">

      {/* ===================== VIEW TABS ===================== */}
      <div className="timesheet-view-tabs">
        <button
          className={view === "WEEK" ? "active-tab" : ""}
          onClick={() => setView("WEEK")}
        >
          Week
        </button>

        <button
          className={view === "MONTH" ? "active-tab" : ""}
          onClick={() => setView("MONTH")}
        >
          Month
        </button>

        <button
          className={view === "SIX" ? "active-tab" : ""}
          onClick={() => setView("SIX")}
        >
          6 Months
        </button>

        <button
          className={view === "YEAR" ? "active-tab" : ""}
          onClick={() => setView("YEAR")}
        >
          Year
        </button>
      </div>



      {/* ===================== WEEK VIEW ===================== */}
      {view === "WEEK" && (
        <>
          {/* SUMMARY */}
          <div className="summary">
            <div className="summary-box">
              <h4>Weekly Total</h4>
              <p>{totalHours} hours</p>
            </div>

            <div className="summary-box">
              <h4>Overtime</h4>
              <p>{overtime} hours</p>
            </div>

            <div className="summary-box">
              <h4>Status</h4>

              <p style={{
                color: status === "SUBMITTED" ? "green" : "#2563eb"
              }}>
                {status}
              </p>
            </div>
          </div>

          {/* WEEK HEADER */}
          <div className="week-header">
            <button onClick={() => changeWeek(-7)}>{"< Previous"}</button>

            <h3>
              {entries.length > 0 &&
                `${entries[0].dateText} - ${entries[6].dateText}`
              }
            </h3>

            <button onClick={() => changeWeek(7)}>{"Next >"}</button>

            <button
              className="today-btn"
              onClick={() => setCurrentWeekStart(getStartOfWeek(new Date()))}
            >
              Today
            </button>
          </div>

          {/* TABLE */}
          <table>
            <thead>
              <tr>
                <th>Day</th>
                <th>Date</th>
                <th>Project</th>
                <th>Hours</th>
                <th>Description</th>
                <th>Action</th>
              </tr>
            </thead>

            <tbody>
              {entries.map((row, index) => (
                <tr
                  key={row.key}
                  className={
                    row.isLeave
                      ? "leave-approved"
                      : row.leaveStatus === "PENDING"
                      ? "leave-pending"
                      : row.leaveStatus === "REJECTED"
                      ? "leave-rejected"
                      : ""
                  }
                >
                  <td>
                    {row.day}

                    {row.leaveStatus && (
                      <div className="leave-label">
                        {row.leaveStatus === "APPROVED"
                          ? `Approved Leave – ${row.leaveType}`
                          : row.leaveStatus === "PENDING"
                          ? `Pending Leave – ${row.leaveType}`
                          : `Rejected Leave – ${row.leaveType}`
                        }
                      </div>
                    )}
                  </td>

                  <td>{row.dateText}</td>

                  <td>
                    <select
                      disabled={status === "SUBMITTED" || row.isLeave}
                      value={row.project}
                      onChange={(e) =>
                        handleChange(index, "project", e.target.value)
                      }
                    >
                      <option value="">Select Project</option>
                      {projects.map((proj, i) => (
                        <option key={i} value={proj}>{proj}</option>
                      ))}
                    </select>
                  </td>

                  <td>
                    <input
                      disabled={status === "SUBMITTED" || row.isLeave}
                      type="number"
                      min="0"
                      max="24"
                      value={row.hours}
                      onChange={(e) =>
                        handleChange(index, "hours", e.target.value)
                      }
                    />
                  </td>

                  <td>
                    <textarea
                      disabled={status === "SUBMITTED" || row.isLeave}
                      value={row.description}
                      onChange={(e) =>
                        handleChange(index, "description", e.target.value)
                      }
                    />
                  </td>

                  <td>
                    <button
                      disabled={status === "SUBMITTED" || row.isLeave}
                      className="remove-btn"
                      onClick={() => removeEntry(index)}
                    >
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* FOOTER */}
          <div className="footer-section">
            <h3>Total Hours: {totalHours}</h3>

            <button
              disabled={status === "SUBMITTED"}
              className="add-btn"
              onClick={addEntry}
            >
              + Add Time Entry
            </button>

            <div className="action-buttons">
              <button
                disabled={status === "SUBMITTED"}
                onClick={() => saveHistory("DRAFT")}
              >
                Save as Draft
              </button>

              <button
                disabled={status === "SUBMITTED"}
                className="submit-btn"
                onClick={() => saveHistory("SUBMITTED")}
              >
                Submit Timesheet
              </button>
            </div>
          </div>
        </>
      )}



      {/* ===================== MONTH VIEW ===================== */}
      {view === "MONTH" && (
        <div className="summary-view">
          <h2>Monthly Timesheet Summary</h2>
          <p>We will show real monthly summary here (safe placeholder for now).</p>
        </div>
      )}

      {/* ===================== 6 MONTH VIEW ===================== */}
      {view === "SIX" && (
        <div className="summary-view">
          <h2>6 Months Timesheet Summary</h2>
          <p>We will show last 6 months analytics summary.</p>
        </div>
      )}

      {/* ===================== YEAR VIEW ===================== */}
      {view === "YEAR" && (
        <div className="summary-view">
          <h2>Yearly Timesheet Summary</h2>
          <p>We will show yearly work statistics.</p>
        </div>
      )}

    </div>
  );
};

export default Timesheet;
